-- Rich content update: Accounting & Finance category

update courses set
  long_description_en = 'Build a solid foundation in accounting principles while getting hands-on practice in 1C, the accounting software used by most companies in Azerbaijan. We cover double-entry bookkeeping, financial statement basics, and day-to-day transaction recording — the exact skills hiring managers look for in junior accounting roles.',
  long_description_az = 'Mühasibat prinsiplərində möhkəm təməl qurarkən, Azərbaycandakı əksər şirkətlərin istifadə etdiyi mühasibat proqramı olan 1C-də praktiki təcrübə əldə edin. İkili giriş mühasibatlığı, maliyyə hesabatları əsasları və gündəlik əməliyyat qeydiyyatını əhatə edirik — kiçik mühasibat vəzifələrində işəgötürənlərin axtardığı dəqiq bacarıqlar.',
  long_description_ru = 'Создайте прочную базу принципов бухучёта, получая практический опыт в 1C — программе, используемой большинством компаний в Азербайджане. Мы охватываем двойную запись, основы финансовой отчётности и ежедневный учёт операций — именно те навыки, которые работодатели ищут для junior-позиций в бухгалтерии.',
  syllabus_en = 'Weeks 1-3: Accounting fundamentals — double-entry, chart of accounts, basic financial statements.
Weeks 4-7: 1C software — navigation, transaction entry, document workflows.
Weeks 8-10: Practical exercises — invoicing, reconciliation, month-end closing basics.
Weeks 11-12: Mock company project — full bookkeeping cycle from scratch.',
  syllabus_az = 'Həftə 1-3: Mühasibat əsasları — ikili giriş, hesablar planı, əsas maliyyə hesabatları.
Həftə 4-7: 1C proqramı — naviqasiya, əməliyyat girişi, sənəd iş axınları.
Həftə 8-10: Praktiki tapşırıqlar — hesab-faktura, uzlaşma, ay sonu bağlama əsasları.
Həftə 11-12: Sınaq şirkət layihəsi — sıfırdan tam mühasibat dövrü.',
  syllabus_ru = 'Недели 1-3: Основы бухучёта — двойная запись, план счетов, базовая финансовая отчётность.
Недели 4-7: Программа 1C — навигация, ввод операций, документооборот.
Недели 8-10: Практические упражнения — выставление счетов, сверка, основы закрытия месяца.
Недели 11-12: Проект учебной компании — полный цикл учёта с нуля.'
where slug = 'muhasibat-ucotu-1c';

update courses set
  long_description_en = 'A practical course on Azerbaijani tax law and reporting requirements. You''ll learn how to calculate and file the taxes most businesses actually deal with — VAT, income tax, and social contributions — plus how to stay compliant with reporting deadlines without scrambling at the last minute.',
  long_description_az = 'Azərbaycan vergi qanunvericiliyi və hesabat tələbləri üzrə praktiki kurs. Əksər şirkətlərin həqiqətən qarşılaşdığı vergiləri — ƏDV, mənfəət vergisi və sosial ayırmalar — necə hesablamağı və təqdim etməyi, həmçinin son dəqiqədə tələsmədən hesabat son tarixlərinə necə əməl etməyi öyrənəcəksiniz.',
  long_description_ru = 'Практический курс по налоговому законодательству и отчётности Азербайджана. Вы научитесь рассчитывать и подавать налоги, с которыми реально работает большинство компаний — НДС, налог на прибыль и социальные отчисления — а также соблюдать сроки отчётности без паники в последний момент.',
  syllabus_en = 'Weeks 1-2: Tax system overview — types of taxes, who pays what, key deadlines.
Weeks 3-5: VAT — calculation, invoicing requirements, common mistakes.
Weeks 6-7: Income tax and social contributions for employees and businesses.
Week 8: Practical filing exercise using real-format documents.',
  syllabus_az = 'Həftə 1-2: Vergi sisteminə baxış — vergi növləri, kim nə ödəyir, əsas son tarixlər.
Həftə 3-5: ƏDV — hesablama, hesab-faktura tələbləri, ümumi səhvlər.
Həftə 6-7: İşçilər və şirkətlər üçün mənfəət vergisi və sosial ayırmalar.
Həftə 8: Real formatlı sənədlərdən istifadə edərək praktiki təqdimat məşqi.',
  syllabus_ru = 'Недели 1-2: Обзор налоговой системы — виды налогов, кто платит и что, ключевые сроки.
Недели 3-5: НДС — расчёт, требования к счетам-фактурам, частые ошибки.
Недели 6-7: Налог на прибыль и социальные отчисления для сотрудников и компаний.
Неделя 8: Практическое упражнение по подаче отчётности на реальных документах.'
where slug = 'vergi-ucotu';

update courses set
  long_description_en = 'Preparation for the globally recognized Certified Internal Auditor designation. The program covers internal audit basics, risk management, governance, and business processes — structured around the official exam syllabus so your study time goes directly toward exam readiness, not generic theory.',
  long_description_az = 'Beynəlxalq səviyyədə tanınan Certified Internal Auditor sertifikatına hazırlıq. Proqram daxili audit əsaslarını, risk idarəetməsini, idarəetmə və biznes proseslərini əhatə edir — rəsmi imtahan proqramı ətrafında strukturlaşdırılıb ki, oxu vaxtınız ümumi nəzəriyyəyə deyil, birbaşa imtahan hazırlığına sərf olunsun.',
  long_description_ru = 'Подготовка к международно признанной квалификации Certified Internal Auditor. Программа охватывает основы внутреннего аудита, управление рисками, корпоративное управление и бизнес-процессы — структурирована вокруг официальной программы экзамена, чтобы время учёбы шло именно на подготовку к экзамену, а не на общую теорию.',
  syllabus_en = 'Part 1: Foundations of internal auditing — standards, ethics, governance.
Part 2: Practice of internal auditing — risk-based audit planning, engagement performance.
Part 3: Business knowledge for internal auditing — IT, finance, and operations fundamentals relevant to audit work.',
  syllabus_az = 'Hissə 1: Daxili auditin əsasları — standartlar, etika, idarəetmə.
Hissə 2: Daxili auditin praktikası — risk əsaslı audit planlaması, icra performansı.
Hissə 3: Daxili audit üçün biznes bilikləri — audit işi ilə bağlı IT, maliyyə və əməliyyat əsasları.',
  syllabus_ru = 'Часть 1: Основы внутреннего аудита — стандарты, этика, управление.
Часть 2: Практика внутреннего аудита — риск-ориентированное планирование, выполнение заданий.
Часть 3: Деловые знания для внутреннего аудита — основы IT, финансов и операций, релевантные аудиту.'
where slug = 'cia';

update courses set
  long_description_en = 'Preparation for the ACCA Financial Accounting (F3) paper — the foundation paper for the entire ACCA qualification. You''ll learn the double-entry system, preparing financial statements, and the underlying principles that every later ACCA paper builds on. Strong here means everything after is easier.',
  long_description_az = 'ACCA Financial Accounting (F3) modulu üzrə hazırlıq — bütün ACCA kvalifikasiyasının təməl modulu. İkili giriş sistemini, maliyyə hesabatlarının hazırlanmasını və sonrakı bütün ACCA modullarının üzərində qurulduğu əsas prinsipləri öyrənəcəksiniz. Burada möhkəm olmaq sonrakı hər şeyin daha asan olması deməkdir.',
  long_description_ru = 'Подготовка к модулю ACCA Financial Accounting (F3) — базовому модулю всей квалификации ACCA. Вы изучите систему двойной записи, подготовку финансовой отчётности и основные принципы, на которых строятся все последующие модули ACCA. Прочная база здесь делает всё дальнейшее проще.',
  syllabus_en = 'Part A: The context and purpose of financial reporting.
Part B: The qualitative characteristics of financial information.
Part C: Double-entry bookkeeping and the accounting equation.
Part D: Preparing basic financial statements.
Part E: Exam-style practice questions and a full mock exam.',
  syllabus_az = 'Hissə A: Maliyyə hesabatlığının kontekst və məqsədi.
Hissə B: Maliyyə məlumatının keyfiyyət xüsusiyyətləri.
Hissə C: İkili giriş mühasibatlığı və mühasibat tənliyi.
Hissə D: Əsas maliyyə hesabatlarının hazırlanması.
Hissə E: İmtahan tipli tapşırıqlar və tam sınaq imtahanı.',
  syllabus_ru = 'Часть A: Контекст и цель финансовой отчётности.
Часть B: Качественные характеристики финансовой информации.
Часть C: Двойная запись и бухгалтерское уравнение.
Часть D: Подготовка базовой финансовой отчётности.
Часть E: Практика заданий в формате экзамена и полный пробный экзамен.'
where slug = 'acca-f3';
